        kind: "comment",
        author: "U2DIA 개발자",
        createdAt: "2026-04-01 16:10",
        content: "이전 답변을 보완합니다. 대시보드는 쿠팡 상품과 샵플링 재고를 3단계 매칭으로 연결합니다. 아래 쿼리가 대시보드의 실제 로직을 SQL로 재현한 것입니다. ■ 매칭 방식 설명 대시보드는 쿠팡 상품(coupang_option_id)에 대해 샵플링 바코드를 아래 순서로 찾습니다. 1순위: 직접 매핑 — barcode_mapping 테이블에 coupang_option_id가 등록된 경우 2순위: 템플릿 브리지 — coupang_template_data 또는 coupang_inbound_template의 barcode를 경유하여 barcode_mapping에서 샵플링 바코드 조회. 세트 상품이면 set_product_mapping으로 단품 바코드 변환. 쿠팡 바코드가 샵플링에 그대로 존재하면 동일 바코드 사용. 3순위: 상품명 fallback — 쿠팡 등록상품명(product_name)이 샵플링 자사상품코드(ptn_goods_cd)와 일치하는 경우 ■ 대시보드 통합 조회 쿼리 (전체 매칭 로직 포함) WITH latest_growth AS ( SELECT MAX(snapshot_date) as dt FROM coupang_sales_snapshots ), latest_inv AS ( SELECT MAX(snapshot_date) as dt FROM shopling_inventory WHERE synced_from_api = true ), inv AS ( SELECT barcode, ptn_goods_cd, product_name as shop_product_name, option_name as shop_option_name, available_stock, real_stock, location FROM shopling_inventory, latest_inv WHERE snapshot_date = latest_inv.dt AND synced_from_api = true ), -- 1순위: barcode_mapping.coupang_option_id 직접 매핑 match1 AS ( SELECT DISTINCT ON (coupang_option_id) coupang_option_id, shopling_barcode FROM barcode_mapping WHERE coupang_option_id IS NOT NULL AND shopling_barcode IS NOT NULL ), -- 템플릿 브리지: option_id -> 쿠팡 barcode tmpl_bridge AS ( SELECT coupang_option_id, barcode as coupang_barcode FROM coupang_template_data WHERE coupang_option_id IS NOT NULL AND barcode IS NOT NULL UNION SELECT coupang_option_id, barcode FROM coupang_inbound_template WHERE coupang_option_id IS NOT NULL AND barcode IS NOT NULL ), -- 2a: 템플릿 barcode -> barcode_mapping -> 샵플링 barcode match2a AS ( SELECT DISTINCT ON (tb.coupang_option_id) tb.coupang_option_id, bm.shopling_barcode FROM tmpl_bridge tb JOIN barcode_mapping bm ON bm.coupang_barcode = tb.coupang_barcode WHERE bm.shopling_barcode IS NOT NULL ), -- 2b: 세트 상품 (쿠팡 barcode = 세트바코드 -> 단품 barcode) match2b AS ( SELECT DISTINCT ON (tb.coupang_option_id) tb.coupang_option_id, sp.single_item_barcode as shopling_barcode FROM tmpl_bridge tb JOIN set_product_mapping sp ON sp.set_barcode = tb.coupang_barcode WHERE sp.single_item_barcode IS NOT NULL ), -- 2c: 쿠팡 barcode가 샵플링 재고에 그대로 존재 match2c AS ( SELECT DISTINCT ON (tb.coupang_option_id) tb.coupang_option_id, inv.barcode as shopling_barcode FROM tmpl_bridge tb JOIN inv ON inv.barcode = tb.coupang_barcode ), -- 3순위: 쿠팡 등록상품명 = 샵플링 자사상품코드 match3 AS ( SELECT DISTINCT ON (g.coupang_option_id) g.coupang_option_id, inv.barcode as shopling_barcode FROM coupang_sales_snapshots g CROSS JOIN latest_growth lg JOIN inv ON inv.ptn_goods_cd = g.product_name WHERE g.snapshot_date = lg.dt AND g.product_name IS NOT NULL AND g.product_name '' ), -- 우선순위 통합: 1 > 2a > 2b > 2c > 3 final_match AS ( SELECT ids.coupang_option_id, COALESCE(m1.shopling_barcode, m2a.shopling_barcode, m2b.shopling_barcode, m2c.shopling_barcode, m3.shopling_barcode) as shopling_barcode, CASE WHEN m1.shopling_barcode IS NOT NULL THEN 'barcode' WHEN m2a.shopling_barcode IS NOT NULL THEN 'barcode' WHEN m2b.shopling_barcode IS NOT NULL THEN 'barcode' WHEN m2c.shopling_barcode IS NOT NULL THEN 'barcode' WHEN m3.shopling_barcode IS NOT NULL THEN 'product_name' ELSE NULL END as match_method FROM ( SELECT DISTINCT coupang_option_id FROM coupang_sales_snapshots, latest_growth WHERE snapshot_date = latest_growth.dt ) ids LEFT JOIN match1 m1 USING (coupang_option_id) LEFT JOIN match2a m2a USING (coupang_option_id) LEFT JOIN match2b m2b USING (coupang_option_id) LEFT JOIN match2c m2c USING (coupang_option_id) LEFT JOIN match3 m3 USING (coupang_option_id) ) -- 최종 결과 SELECT g.coupang_option_id, g.product_name, g.option_name, g.product_grade, g.available_stock AS coupang_available_stock, g.incoming_stock AS coupang_incoming_stock, g.sales_7d_qty, g.sales_30d_qty, (g.sales_30d_qty * 2) AS sales_60d_qty, g.extracted_set_qty, g.recommended_inbound_qty, g.stock_depletion_date, g.is_item_winner, fm.shopling_barcode, COALESCE(fm.match_method, '없음') AS match_method, inv.shop_product_name AS shopling_product_name, inv.shop_option_name AS shopling_option_name, inv.available_stock AS shopling_available_stock, inv.real_stock AS shopling_real_stock, inv.location AS shopling_location, ov.optimal_upload_qty, ov.updated_by_name AS optimal_saved_by, ov.updated_at AS optimal_saved_at, ss.safety_stock AS shopling_safety_stock, GREATEST(g.sales_30d_qty, ROUND(g.sales_7d_qty / 7.0 * 3)) * COALESCE(g.extracted_set_qty, 1) AS raw_inbound_qty, CASE WHEN fm.shopling_barcode IS NULL THEN 0 WHEN COALESCE(inv.available_stock, 0) inv.available_stock THEN inv.available_stock ELSE GREATEST(g.sales_30d_qty, ROUND(g.sales_7d_qty / 7.0 * 3)) * COALESCE(g.extracted_set_qty, 1) END AS optimal_upload_qty_calculated FROM coupang_sales_snapshots g CROSS JOIN latest_growth lg LEFT JOIN final_match fm ON fm.coupang_option_id = g.coupang_option_id LEFT JOIN inv ON inv.barcode = fm.shopling_barcode LEFT JOIN optimal_upload_overrides ov ON ov.coupang_option_id = g.coupang_option_id LEFT JOIN safety_stock_settings ss ON ss.coupang_option_id = g.coupang_option_id WHERE g.snapshot_date = lg.dt ORDER BY g.product_name, g.option_name; ■ 참고 - match_method 컬럼: barcode = 바코드 매핑, product_name = 상품명 매칭, 없음 = 미매칭 - optimal_upload_qty: 사용자가 수동 편집한 값 (optimal_upload_overrides) - optimal_upload_qty_calculated: 시스템이 자동 계산한 추천값 - 덮어쓰기 확인: optimal_saved_by (수정자), optimal_saved_at (수정일시) 참조 - 페이지네이션: 쿼리 끝에 LIMIT 50 OFFSET 0 추가",
